// ---------------------------------------------------------------------------
// Validation helpers
// ---------------------------------------------------------------------------
export function getGoldSetByBucket(bucket) {
    return GOLD_SET.filter((e) => e.bucket === bucket);
}
export function getGoldSetByTag(tag) {
    return GOLD_SET.filter((e) => e.tags.includes(tag));
}
export function validateGoldSetDistribution() {
    const ready = getGoldSetByBucket("ready").length;
    const nc = getGoldSetByBucket("needs_clarification").length;
    const blocked = getGoldSetByBucket("blocked").length;
    const acAlias = getGoldSetByTag("ac-alias").length;
    const repoAmb = getGoldSetByTag("repo-ambiguity").length;
    const permSensitive = getGoldSetByTag("permission-sensitive").length;
    const errors = [];
    if (GOLD_SET.length < 48)
        errors.push(`Gold set has only ${GOLD_SET.length} entries (need ≥ 48)`);
    if (ready < 16)
        errors.push(`Only ${ready} ready entries (need ≥ 16)`);
    if (nc < 16)
        errors.push(`Only ${nc} needs_clarification entries (need ≥ 16)`);
    if (blocked < 16)
        errors.push(`Only ${blocked} blocked entries (need ≥ 16)`);
    if (acAlias < 10)
        errors.push(`Only ${acAlias} ac-alias tagged entries (need ≥ 10)`);
    if (repoAmb < 10)
        errors.push(`Only ${repoAmb} repo-ambiguity tagged entries (need ≥ 10)`);
    if (permSensitive < 6)
        errors.push(`Only ${permSensitive} permission-sensitive tagged entries (need ≥ 6)`);
    return {
        ready,
        needs_clarification: nc,
        blocked,
        ac_alias: acAlias,
        repo_ambiguity: repoAmb,
        permission_sensitive: permSensitive,
        valid: errors.length === 0,
        errors,
    };
}
